 45→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 46→  switch (entry.type) {
 47→    case 'label':
 48→      return (
 49→        <DetailMetadata.Label
 50→          key={index}
 51→          title={entry.title}
 52→          text={entry.text}
 53→        />
 54→      );
 55→    case 'link':
 56→      return (
 57→        <DetailMetadata.Link
 58→          key={index}
 59→          title={entry.title}
 60→          text={entry.text}
 61→          target={entry.target}
 62→        />
 63→      );
 64→    case 'tag-list':
 65→      return (
 66→        <DetailMetadata.TagList key={index} title={entry.title}>
 67→          {entry.tags.map(tag => (
 68→            <DetailMetadata.Tag
 69→              key={tag.text}
 70→              text={tag.text}
 71→              color={tag.color}
 72→            />
 73→          ))}
 74→        </DetailMetadata.TagList>
 75→      );
 76→    case 'separator':
 77→      return <DetailMetadata.Separator key={index} />;
 78→  }
 79→}
