214→
215→  const registrySections = useMemo(() => getSections(), []);
216→
217→  const filtered = useMemo(() => {
218→    let sections = registrySections;
219→    if (filterValue === 'commands') {
220→      sections = sections.filter(
221→        s => s.title === 'Suggestions' || s.title === 'Commands',
222→      );
223→    } else if (filterValue === 'applications') {
224→      sections = sections.filter(s => s.title === 'Applications');
225→    }
226→
227→    const result = query ? searchCommands(query) : sections;
228→
229→    const filteredResult = query
230→      ? result
231→          .map(s => {
232→            if (filterValue === 'commands') {
233→              return s.title === 'Suggestions' || s.title === 'Commands'
234→                ? s
235→                : {
236→                    ...s,
237→                    items: [],
238→                  };
239→            }
240→            if (filterValue === 'applications') {
241→              return s.title === 'Applications'
242→                ? s
243→                : {
244→                    ...s,
245→                    items: [],
246→                  };
247→            }
248→            return s;
249→          })
250→          .filter(s => s.items.length > 0)
251→      : result;
252→
253→    const allFlatItems = sections.flatMap(s => s.items);
254→    const favoriteItems = favoriteIds
255→      .map(id => allFlatItems.find(item => item.id === id))
256→      .filter((item): item is ListItemData => !!item);
257→
258→    if (query) {
259→      const lower = query.toLowerCase();
260→      const filteredFavs = favoriteItems.filter(
261→        item =>
262→          item.title.toLowerCase().includes(lower) ||
263→          item.subtitle?.toLowerCase().includes(lower),
264→      );
265→      if (filteredFavs.length > 0) {
266→        const favIds = new Set(filteredFavs.map(f => f.id));
267→        const dedupedSections = filteredResult
268→          .map(s => ({
269→            ...s,
270→            items: s.items.filter(item => !favIds.has(item.id)),
