 1→import { useCallback, useMemo, useState } from 'react';
 2→
 3→const STORAGE_KEY = 'raycast-favorites';
 4→
 5→function loadFavorites(): string[] {
 6→  try {
 7→    const stored = localStorage.getItem(STORAGE_KEY);
 8→    if (stored) {
 9→      const parsed: unknown = JSON.parse(stored);
10→      if (Array.isArray(parsed) && parsed.every(id => typeof id === 'string')) {
11→        return parsed;
12→      }
13→    }
14→  } catch {
15→    return [];
16→  }
17→  return [];
18→}
19→
20→function saveFavorites(ids: string[]) {
21→  try {
22→    localStorage.setItem(STORAGE_KEY, JSON.stringify(ids));
23→  } catch {
24→    // no-op
25→  }
26→}
27→
28→export function useFavorites() {
29→  const [favoriteIds, setFavoriteIds] = useState<string[]>(loadFavorites);
30→
31→  const favoriteSet = useMemo(() => new Set(favoriteIds), [favoriteIds]);
32→
33→  const isFavorite = useCallback(
34→    (id: string) => favoriteSet.has(id),
35→    [favoriteSet],
36→  );
37→
38→  const toggleFavorite = useCallback((id: string) => {
39→    setFavoriteIds(prev => {
40→      const next = prev.includes(id)
41→        ? prev.filter(fid => fid !== id)
42→        : [
43→            ...prev,
44→            id,
45→          ];
46→      saveFavorites(next);
47→      return next;
48→    });
49→  }, []);
50→
51→  const moveFavorite = useCallback((id: string, direction: 'up' | 'down') => {
52→    setFavoriteIds(prev => {
53→      const idx = prev.indexOf(id);
54→      if (idx === -1) return prev;
55→      const targetIdx = direction === 'up' ? idx - 1 : idx + 1;
56→      if (targetIdx < 0 || targetIdx >= prev.length) return prev;
57→      const next = [...prev];
58→      next[idx] = prev[targetIdx]!;
59→      next[targetIdx] = prev[idx]!;
60→      saveFavorites(next);
61→      return next;
62→    });
63→  }, []);
64→
65→  return {
66→    favoriteIds,
67→    isFavorite,
68→    toggleFavorite,
69→    moveFavorite,
70→  };
71→}
