 1→import { useCallback, useEffect, useState } from 'react';
 2→
 3→type ThemePreference = 'dark' | 'light' | 'system';
 4→type ResolvedTheme = 'dark' | 'light';
 5→
 6→const STORAGE_KEY = 'raycast-theme';
 7→
 8→function getSystemTheme(): ResolvedTheme {
 9→  return window.matchMedia('(prefers-color-scheme: light)').matches
10→    ? 'light'
11→    : 'dark';
12→}
13→
14→function resolveTheme(preference: ThemePreference): ResolvedTheme {
15→  return preference === 'system' ? getSystemTheme() : preference;
16→}
17→
18→function loadPreference(): ThemePreference {
19→  const stored = localStorage.getItem(STORAGE_KEY);
20→  if (stored === 'dark' || stored === 'light' || stored === 'system') {
21→    return stored;
22→  }
23→  return 'dark';
24→}
25→
26→function applyTheme(theme: ResolvedTheme) {
27→  document.documentElement.setAttribute('data-theme', theme);
28→}
29→
30→export function useTheme() {
31→  const [preference, setPreference] = useState<ThemePreference>(loadPreference);
32→  const [resolved, setResolved] = useState<ResolvedTheme>(() =>
33→    resolveTheme(loadPreference()));
34→
35→  useEffect(() => {
36→    const r = resolveTheme(preference);
37→    setResolved(r);
38→    applyTheme(r);
39→  }, [preference]);
40→
41→  useEffect(() => {
42→    if (preference !== 'system') return;
43→
44→    const mql = window.matchMedia('(prefers-color-scheme: light)');
45→    const handler = () => {
46→      const r = resolveTheme('system');
47→      setResolved(r);
48→      applyTheme(r);
49→    };
50→    mql.addEventListener('change', handler);
51→    return () => mql.removeEventListener('change', handler);
52→  }, [preference]);
53→
54→  const setTheme = useCallback((value: ThemePreference) => {
55→    setPreference(value);
56→    localStorage.setItem(STORAGE_KEY, value);
57→  }, []);
58→
59→  return {
60→    preference,
61→    resolved,
62→    setTheme,
63→  };
64→}
